1. using Microsoft.ML;
2. using Microsoft.ML.Data;
3. using TicketClassifier.Models;
4. 
5. namespace TicketClassifier.Services;
6. 
7. public class TicketClassifierService
8. {
9.     private readonly MLContext _mlContext;
10.     private readonly ITransformer _model;
11.     private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
12.     private readonly EvaluationMetrics _metrics;
13.     private readonly string[] _categoryLabels;
14. 
15.     public TicketClassifierService(string dataPath)
16.     {
17.         _mlContext = new MLContext(seed: 0);
18. 
19.         var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
20.             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
21. 
22.         var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
23.             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
24.             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
25.             .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
26.             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
27.             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));
28. 
29.         // Train/test split for evaluation
30.         var trainTestSplit = _mlContext.Data.TrainTestSplit(dataView, testFraction: 0.3);
31. 
32.         _model = pipeline.Fit(trainTestSplit.TrainSet);
33. 
34.         // Evaluate
35.         var predictions = _model.Transform(trainTestSplit.TestSet);
36.         var mlMetrics = _mlContext.MulticlassClassification.Evaluate(predictions, "Label");
37. 
38.         _metrics = new EvaluationMetrics
39.         {
40.             MacroAccuracy = (float)mlMetrics.MacroAccuracy,
41.             MicroAccuracy = (float)mlMetrics.MicroAccuracy,
42.             LogLoss = (float)mlMetrics.LogLoss,
43.             LogLossReduction = (float)mlMetrics.LogLossReduction
44.         };
45. 
46.         // Retrain on full data for production use
47.         _model = pipeline.Fit(dataView);
48.         _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);
49. 
50.         // Extract label names for confidence mapping
51.         var outputSchema = _model.GetOutputSchema(dataView.Schema);
52.         var scoreColumn = outputSchema["Score"];
53.         var slotNames = new VBuffer<ReadOnlyMemory<char>>();
54.         scoreColumn.Annotations.GetValue("SlotNames", ref slotNames);
55.         _categoryLabels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();
56.     }
57. 
58.     public PredictionResponse Predict(TicketRequest request)
59.     {
60.         var ticketData = new TicketData
61.         {
62.             Subject = request.Subject,
63.             Description = request.Description,
64.             Priority = request.Priority
65.         };
66. 
67.         var prediction = _predictionEngine.Predict(ticketData);
68. 
69.         var confidence = new Dictionary<string, float>();
70.         for (int i = 0; i < _categoryLabels.Length; i++)
71.         {
72.             confidence[_categoryLabels[i]] = prediction.Score[i];
73.         }
74. 
75.         return new PredictionResponse
76.         {
77.             PredictedCategory = prediction.PredictedCategory,
78.             Confidence = confidence
79.         };
80.     }
81. 
82.     public EvaluationMetrics GetMetrics() => _metrics;
83. }
84.

